<script setup lang="ts">import{computed}from'vue';import{useRouter}from'vue-router';import{ChevronDown,Menu,LogOut}from'lucide-vue-next';import{useAuthStore}from'@/stores/auth';import{useUiStore}from'@/stores/ui';defineProps<{title:string}>();const auth=useAuthStore(),ui=useUiStore(),router=useRouter();const initials=computed(()=>String(auth.user?.user_metadata?.display_name??auth.user?.email??'U').split(/[ @]/).filter(Boolean).slice(0,2).map(x=>x[0]?.toUpperCase()).join(''));async function logout(){await auth.signOut();await router.replace('/auth')}</script><template><header><button class="icon-button menu" aria-label="Открыть меню" @click="ui.sidebarOpen=true"><Menu/></button><div><p>Рабочее пространство</p><div class="workspace">{{auth.organization?.name??'Загрузка…'}} <ChevronDown :size="15"/></div></div><div class="header-title">{{title}}</div><div class="avatar">{{initials}}</div><button class="icon-button" title="Выйти" @click="logout"><LogOut :size="17"/></button></header></template>